INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e2608fa0-8420-4110-97b4-62928c27aa9c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue State Management — Local, Lifted, Provide/Inject, or Pinia?$escape$,
  $escape$Vue gives you four tiers of state, each with a clear use case. Local `ref()`/`reactive()` inside `<script setup>` is the default — if only one component needs it, keep it there. Lift to props/emits when a parent needs to coordinate two siblings; use `defineProps` and `defineEmits` to keep the contract explicit. Reach for `provide`/`inject` when you have deep component trees and prop-drilling becomes painful — pass a reactive `ref` via `provide` so descendants stay reactive without coupling to every ancestor. Pinia is the answer when state spans unrelated parts of the app, needs to persist across route changes, or requires devtools/time-travel debugging. The most common mistake is skipping directly to Pinia for everything. A form's dirty state is local. A selected tab shared between two siblings is lifted. A theme preference passed three levels deep is provided. User session data accessed across five unrelated views belongs in a Pinia store. Match the scope of the state to the scope of the solution.$escape$,
  $escape$// Provide reactive state deep in the tree
// parent.vue
const theme = ref<'light' | 'dark'>('light')
provide('theme', theme)

// deep-child.vue
const theme = inject<Ref<'light' | 'dark'>>('theme')!

// Pinia — for truly cross-cutting state
export const useAuthStore = defineStore('auth', () => {
  const user = ref<User | null>(null)
  const isLoggedIn = computed(() => user.value !== null)
  return { user, isLoggedIn }
})$escape$,
  $escape$typescript$escape$,
