INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'acdf9ce8-0988-425a-870c-bcf8766e3292',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue + TanStack Query — Server State Doesn't Belong in Pinia$escape$,
  $escape$Most Vue apps over-reach with Pinia, stuffing it with data that's really owned by the server. Server state has a different contract: it goes stale, needs background refetching, and must handle loading/error lifecycle. Client state (UI toggles, form drafts, selected tab) is yours to own — Pinia is perfect there.

`@tanstack/vue-query` handles server state with composables that integrate directly with Vue's reactivity. Pass a reactive ref as a query key and the query auto-refetches when it changes — no watcher needed. `useQuery` returns `data`, `isPending`, `isError` as computed refs, so templates stay declarative.

For mutations, `useMutation` gives you `mutate()` and `onSuccess` to invalidate stale queries via `queryClient.invalidateQueries`. This keeps your Pinia stores thin — only UI state lives there — and eliminates the manual fetch-store-display ceremony that plagues most Vue data layers. Cache TTL, deduplication, and background sync come for free.$escape$,
  $escape$import { useQuery, useMutation, useQueryClient } from '@tanstack/vue-query'
import { ref } from 'vue'

const userId = ref(1)

const { data: user, isPending } = useQuery({
  queryKey: ['user', userId],   // reactive: refetches when userId changes
  queryFn: () => fetch(`/api/users/${userId.value}`).then(r => r.json()),
  staleTime: 60_000,
})

const queryClient = useQueryClient()
const { mutate: updateUser } = useMutation({
  mutationFn: (payload) => fetch(`/api/users/${userId.value}`, { method: 'PATCH', body: JSON.stringify(payload) }),
  onSuccess: () => queryClient.invalidateQueries({ queryKey: ['user', userId] }),
})$escape$,
  $escape$javascript$escape$,
