INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7626e5a3-349f-4acc-b02b-76b1492279c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Security — v-html, Token Storage, and Input Sanitization$escape$,
  $escape$Vue's `v-html` directive is the equivalent of React's `dangerouslySetInnerHTML` — it bypasses Vue's template compiler and injects raw HTML directly into the DOM. Never pass user-controlled data through it without sanitization. Use DOMPurify before binding: `v-html="sanitize(userContent)"` where `sanitize` wraps `DOMPurify.sanitize()`. For token storage, avoid `localStorage` for JWTs — it's accessible to any script on the page, making XSS attacks trivially extractable. Prefer `httpOnly` cookies managed server-side. If you must use client storage, scope tokens to `sessionStorage` and pair with a short expiry. For input sanitization in forms, Vue's `v-model` does not sanitize — it binds raw strings. Validate and strip on submission using a schema library like Zod or Valibot before sending to your API. Composables are a clean pattern here: a `useSanitizedForm()` composable can wrap reactive form state, run Zod `.parse()` on submit, and expose only safe values to the template layer. Defense-in-depth means sanitizing at the component boundary, not just the backend.$escape$,
  $escape$import DOMPurify from 'dompurify'
import { z } from 'zod'
import { ref } from 'vue'

// Safe v-html usage
const sanitize = (html: string) => DOMPurify.sanitize(html)

// useSanitizedForm composable
const schema = z.object({ comment: z.string().max(500).trim() })

export function useSanitizedForm() {
  const comment = ref('')
  const submit = () => {
    const result = schema.safeParse({ comment: comment.value })
    if (!result.success) return result.error.flatten()
    return result.data // safe to send to API
  }
  return { comment, submit }
}$escape$,
  $escape$typescript$escape$,
