INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f2866043-8c38-4364-9b96-ee01a4e17541',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Web Vitals — How Component Patterns Drive LCP, CLS, and INP$escape$,
  $escape$Vue's component model directly shapes all three Core Web Vitals. For LCP, wrapping above-the-fold content in `defineAsyncComponent` or `<Suspense>` delays the largest paint — keep hero images and primary headings in eagerly loaded components. Add `fetchpriority="high"` directly on the LCP `<img>`; Vue doesn't do this automatically. For CLS, `v-if` is the primary culprit: it removes and reinserts DOM nodes, shifting surrounding content. Switch to `v-show` for toggled UI that exists on initial load, and add fixed-height skeleton placeholders before `v-for` lists arrive asynchronously — Vue reserves no space by default. For INP, Vue's scheduler batches reactive writes, but expensive `computed` properties called inside event handlers still run synchronously on the main thread. Use `shallowRef` for large arrays to bypass deep reactive traversal. Debounce `v-model` bindings on search inputs with `useDebounceFn` from VueUse. Avoid `watch({ deep: true, immediate: true })` on large objects — it blocks the frame before the browser can paint a response.$escape$,
  $escape$import { shallowRef, ref } from 'vue'
import { useDebounceFn } from '@vueuse/core'

// INP: shallowRef skips deep proxy traversal on large datasets
const rows = shallowRef<Row[]>([])

const query = ref('')
// INP: debounce prevents every keystroke from blocking the main thread
const setQuery = useDebounceFn((v: string) => { query.value = v }, 200)

// Template:
// CLS: v-show keeps DOM node in tree; min-height reserves layout space
// <section v-show="rows.length" style="min-height:320px">
//   <RowCard v-for="r in rows" :key="r.id" :data="r" />
// </section>$escape$,
  $escape$typescript$escape$,
