INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6785468a-ee49-484d-9e6d-a5c5f5301194',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue WebSockets — Singleton Connection, Reconnection, and Optimistic UI$escape$,
  $escape$A singleton WebSocket in Vue lives at module scope, outside the composable function body — so multiple component instances share one connection rather than opening one per mount. Declare `let socket: WebSocket | null = null` at the top of `useChat.ts`; the composable checks `socket.readyState` before reconnecting.

Reconnection logic belongs in the `onclose` handler. A simple exponential backoff uses a module-level `reconnectDelay` that doubles on each failure and resets inside `onopen`. Clear any pending timeout in `onUnmounted` to prevent stale callbacks after the last consumer unmounts.

Optimistic UI means pushing outbound messages into the reactive `ref` array before `socket.send()` fires. If you need rollback on failure, track messages as `{ id, text, status: 'pending' | 'sent' | 'failed' }` and update `status` inside `onmessage`. Vue's fine-grained reactivity makes this clean — mutating `messages.value` triggers targeted re-renders without manual DOM work. For server-confirmed ordering, reconcile by message ID rather than array index to avoid flicker.$escape$,
  $escape$// useChat.ts — module-level singleton
let socket: WebSocket | null = null
let reconnectTimer: ReturnType<typeof setTimeout>

export function useChat(url: string) {
  const messages = ref<{ id: string; text: string; status: 'pending' | 'sent' }[]>([])

  function connect() {
    socket = new WebSocket(url)
    socket.onopen = () => clearTimeout(reconnectTimer)
    socket.onmessage = (e) => {
      const { id } = JSON.parse(e.data)
      const m = messages.value.find(m => m.id === id)
      if (m) m.status = 'sent'
    }
    socket.onclose = () => { reconnectTimer = setTimeout(connect, 2000) }
  }

  function send(text: string) {
    const id = crypto.randomUUID()
    messages.value.push({ id, text, status: 'pending' }) // optimistic
    socket?.send(JSON.stringify({ id, text }))
  }

  if (!socket || socket.readyState > 1) connect()
  onUnmounted(() => clearTimeout(reconnectTimer))

  return { messages, send }
}$escape$,
  $escape$typescript$escape$,
