INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f774fffe-d19b-4dd4-ae48-8824652427bc',
  '00000000-0000-0000-0000-000000000001',
  $escape$vue API Layer — Single Axios Instance, Interceptors, No Raw fetch in Components$escape$,
  $escape$Scattering `fetch()` calls across Vue components couples your UI to transport logic and makes auth changes a find-and-replace nightmare. Instead, create a single Axios instance in `src/api/client.ts` and export it as your app's only HTTP primitive.

Attach a request interceptor that reads the auth token from your Pinia store — not from `localStorage` directly — so the interceptor stays reactive to token refreshes. Add a response interceptor that catches 401s and either calls your refresh endpoint or redirects to login, then retries the original request with `error.config`.

Wrap domain calls in thin composables — `useUserApi()`, `usePostsApi()` — that import the shared client. Components call composables, composables call the client, the client talks to the network. Nothing else does. This makes mocking trivial in Vitest: replace the client import with `vi.mock('../api/client')` once, and every composable test gets a clean fake with zero component coupling. Interceptors also centralize logging, `AbortController` timeout policies, and base URL switching between environments.$escape$,
  $escape$// src/api/client.ts
import axios from 'axios'
import { useAuthStore } from '@/stores/auth'

const client = axios.create({ baseURL: import.meta.env.VITE_API_URL })

client.interceptors.request.use((config) => {
  const { token } = useAuthStore()
  if (token) config.headers.Authorization = `Bearer ${token}`
  return config
})

client.interceptors.response.use(
  (res) => res,
  async (err) => {
    if (err.response?.status === 401) {
      await useAuthStore().refresh()
      return client(err.config)
    }
    return Promise.reject(err)
  }
)

export default client$escape$,
