INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '73d3f9d6-220d-4015-9320-d90063ade3b3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Animations — CSS Transitions, Framer Motion, and prefers-reduced-motion$escape$,
  $escape$Vue's built-in `<Transition>` and `<TransitionGroup>` components handle simple state changes cleanly — enter/leave fades, list reorders, modal slides. For these, CSS is the right tool: zero JS overhead, GPU-composited transforms, and trivially respectable of user motion preferences via `@media (prefers-reduced-motion: reduce)` in your transition classes.

For orchestrated sequences — staggered card reveals, drag-and-drop with spring physics, shared element transitions — reach for `@vueuse/motion` (Vue-native bindings over Motion's engine). It exposes a `v-motion` directive and `useMotion()` composable that integrate naturally with Vue's reactivity system.

Always gate complex animations: read `window.matchMedia('(prefers-reduced-motion: reduce)').matches` or use VueUse's `usePreferredReducedMotion()`. Pass the result into your motion variant to swap spring animations for instant state changes. Never rely solely on CSS media queries when JS controls your animation engine — the directive won't pick them up automatically.$escape$,
  $escape$<script setup lang="ts">
import { usePreferredReducedMotion } from '@vueuse/core'

const reduced = usePreferredReducedMotion()

const motionVariants = computed(() => ({
  initial: { opacity: 0, y: reduced.value === 'reduce' ? 0 : 24 },
  enter:   { opacity: 1, y: 0, transition: { duration: reduced.value === 'reduce' ? 0 : 400 } },
}))
</script>

<template>
  <div v-motion :initial="motionVariants.initial" :enter="motionVariants.enter">
    <slot />
  </div>
</template>$escape$,
  $escape$typescript$escape$,
