INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd0b7affa-c6c7-46f2-a4f0-2959ae644852',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Global UI Patterns — Toast, Modal & Confirmation Hooks at App Root$escape$,
  $escape$Lifting UI state like toasts, modals, and confirmation dialogs to app root eliminates prop drilling and keeps components clean. In Vue 3, the idiomatic approach combines `provide`/`inject` with composables. Define a `useToast()` composable backed by a reactive array provided at `App.vue` root — any component injects and calls `toast.add()` without imports beyond the composable. Modals follow the same pattern: a `useModal()` composable exposes `open(component, props)` and renders via `<component :is>` in a root `ModalHost.vue`. Confirmation dialogs are best implemented as promise-based hooks — `useConfirm().ask('Delete item?')` returns a `Promise<boolean>`, letting callers use `await` naturally inside async handlers. The key Vue detail: use `shallowRef` for the modal component to avoid deep reactivity overhead, and `markRaw()` the component reference before storing it. Providing these composables via `app.provide()` in `main.ts` (rather than inside `App.vue`) makes them available before the component tree mounts, which matters for router guards that trigger toasts.$escape$,
  $escape$// main.ts
import { createApp } from 'vue'
import App from './App.vue'
import { toastPlugin } from './plugins/toast'

const app = createApp(App)
app.use(toastPlugin)
app.mount('#app')

// composables/useConfirm.ts
import { inject } from 'vue'
import type { ConfirmService } from '@/plugins/confirm'

export function useConfirm() {
  const confirm = inject<ConfirmService>('confirm')!
  return {
    ask: (message: string): Promise<boolean> => confirm.ask(message)
  }
}

// In any component
const { ask } = useConfirm()
async function handleDelete() {
  if (await ask('Delete this item?')) {
    await deleteItem(id)
  }
}$escape$,
