INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd6907967-7f43-4ae5-b906-b8941a3cfccb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Bundle Optimization — Tree-Shaking, Lazy Routes, and Analyzing What You Ship$escape$,
  $escape$Vue 3 + Vite gives you tree-shaking out of the box, but you can still bloat your bundle with careless imports. The most common offender: importing all of a UI library instead of individual components. With libraries like Vuestic or PrimeVue, always use their dedicated Vite/rollup plugins for auto-imported tree-shaking rather than a monolithic `app.use(PrimeVue)` with everything registered globally.

For heavy components — rich text editors, chart libraries, PDF viewers — use Vue's `defineAsyncComponent` to defer loading until the component actually mounts. Pair this with Vue Router's lazy route syntax (`component: () => import('./views/Dashboard.vue')`) so Vite emits separate chunks per route automatically.

To audit what you're actually shipping, run `npx vite-bundle-visualizer` (or `rollup-plugin-visualizer` in `vite.config.ts`). It renders an interactive treemap of your dist. Target any single chunk over 200kb — either split it with `build.rollupOptions.output.manualChunks` or lazy-load the offending import.$escape$,
  $escape$// vite.config.ts
import { visualizer } from 'rollup-plugin-visualizer';
import { defineConfig } from 'vite';

export default defineConfig({
  plugins: [visualizer({ open: true, gzipSize: true })],
  build: {
    rollupOptions: {
      output: {
        manualChunks: {
          'chart': ['chart.js', 'vue-chartjs'],
          'editor': ['@tiptap/vue-3', '@tiptap/starter-kit'],
        },
      },
    },
  },
});

// In a component:
const HeavyEditor = defineAsyncComponent(() => import('./HeavyEditor.vue'));$escape$,
  $escape$typescript$escape$,
