INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2536ee8f-403c-495d-87e6-b08cad9429b9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue Production Monitoring — Sentry, Web Vitals, and Source Maps Done Right$escape$,
  $escape$Sentry integrates with Vue via its dedicated plugin. Install `@sentry/vue` and initialize it in `main.ts` before mounting your app — pass the `app` instance so Sentry can hook into Vue's global error handler and capture component-level errors with full context, including the failing component name and props trace.

Source maps are critical: without them, Sentry shows minified stack traces. Use `@sentry/vite-plugin` in `vite.config.ts` to automatically upload source maps on build. Set `sourcemap: 'hidden'` so maps are uploaded but never served publicly.

For Web Vitals, pair Sentry's performance tracing with the `web-vitals` package. Report LCP, CLS, and INP directly to Sentry as custom measurements, or use `useRouter()` from Vue Router to instrument navigation spans — Sentry's Vue integration automatically creates transactions per route change when `routingInstrumentation` is configured.

Filter noise early: use `beforeSend` to drop errors from browser extensions and set `tracesSampleRate` to 0.1–0.2 in production to avoid quota exhaustion.$escape$,
  $escape$// main.ts
import * as Sentry from '@sentry/vue'
import { createApp } from 'vue'
import { router } from './router'

const app = createApp(App)

Sentry.init({
  app,
  dsn: import.meta.env.VITE_SENTRY_DSN,
  integrations: [Sentry.browserTracingIntegration({ router })],
  tracesSampleRate: 0.1,
  beforeSend(event) {
    if (event.exception?.values?.[0]?.stacktrace?.frames?.some(f => f.filename?.includes('extension://'))) return null
    return event
  },
})

app.use(router).mount('#app')$escape$,
  $escape$typescript$escape$,
