INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '47c8c7e4-13fa-47fd-92e3-cdf2d7a2acfb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vue's Reactivity Model — How the Proxy-Based System Decides What Re-Runs$escape$,
  $escape$Vue 3's reactivity is built on ES Proxy objects. When you call `reactive()` or `ref()`, Vue wraps your data in a Proxy that intercepts `get` and `set` operations. During a component's render (or inside `watchEffect`), Vue's active effect tracker records every reactive property accessed — this is dependency tracking. When a tracked property mutates, only the effects that accessed it are re-queued.

Unlike React's top-down diffing (re-render subtree, then reconcile), Vue tracks at the property level. `ref<number>(0)` exposes a `.value` getter — accessing it inside `<template>` or a `computed()` registers the dependency. Mutating `.value` surgically re-runs only affected computed properties and component renders.

`computed()` is lazy and cached: it re-evaluates only when its own tracked dependencies change, not on every parent render. This means deeply nested components reading stable computed values pay zero re-render cost — no `memo()` equivalent needed. Avoid destructuring reactive objects (`const { count } = state`) — it breaks the Proxy chain and silently kills reactivity.$escape$,
  $escape$import { reactive, computed, watchEffect } from 'vue'

const state = reactive({ count: 0, multiplier: 2 })

// Computed caches and re-runs ONLY when count or multiplier changes
const result = computed(() => state.count * state.multiplier)

// watchEffect auto-tracks: re-runs when result.value is accessed and changes
watchEffect(() => {
  console.log('result:', result.value) // tracks result
})

state.count++       // triggers computed + watchEffect
state.multiplier++  // triggers computed + watchEffect

// BAD: destructuring breaks Proxy tracking
// const { count } = state  ← count is now a plain number, not reactive$escape$,
  $escape$javascript$escape$,
